composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    depends_on:
      - {{serviceName}}-db
{{ports}}
    volumes:
      - {{env.MATOMO_DATA_PATH}}:/var/www/html
    environment:
      MATOMO_DATABASE_HOST: {{serviceName}}-db
      MATOMO_DATABASE_ADAPTER: mysql
      MATOMO_DATABASE_TABLES_PREFIX: matomo_
      MATOMO_DATABASE_USERNAME: {{env.MATOMO_DB_USER}}
      MATOMO_DATABASE_PASSWORD: {{env.MATOMO_DB_PASSWORD}}
      MATOMO_DATABASE_DBNAME: {{env.MATOMO_DB_NAME}}
  {{serviceName}}-db:
    image: mariadb:11
    container_name: {{containerName}}-db
    restart: unless-stopped
    command: --max-allowed-packet=64MB
    volumes:
      - {{env.MATOMO_DB_PATH}}:/var/lib/mysql
    environment:
      MARIADB_DATABASE: {{env.MATOMO_DB_NAME}}
      MARIADB_USER: {{env.MATOMO_DB_USER}}
      MARIADB_PASSWORD: {{env.MATOMO_DB_PASSWORD}}
      MARIADB_ROOT_PASSWORD: {{env.MATOMO_DB_ROOT_PASSWORD}}
